filter(priority) {
  return this.todos.filter(todo => todo.priority === priority);
}

overdue() {
  const today = new Date();
  today.setHours(0, 0, 0, 0);

  return this.todos.filter(todo =>
    todo.dueDate &&
    new Date(todo.dueDate) < today &&
    !todo.completed
  );
}

list() {
  return this.todos;
}
